                x.rightNode = y;
                y.height =
                    Math.max(this.getHeight(y.leftNode), this.getHeight(y.rightNode)) + 1;
                x.height =
                    Math.max(this.getHeight(x.leftNode), this.getHeight(x.rightNode)) + 1;
